  async def test_update_duende_marker_implementation_get_updated_content_only_reads_path_does_not_modify_it(
      self) -> None:
    # ✨ update_duende_marker_implementation_get_updated_content: Only reads `path`, does not modify it.
    with tempfile.TemporaryDirectory() as temp_dir:
      temp_file_path = pathlib.Path(temp_dir) / "test_file.py"
      original_content_lines = [
          "            # Some initial content",
          "            def foo():",
          "                # ✨ my_marker",
          "                print(\"original content\")",
          "                # ✨",
      ]
      original_content = '\n'.join(original_content_lines)

      async with aiofiles.open(temp_file_path, 'w') as f:
        await f.write(original_content)

      # Read the file content before calling _get_updated_content
      async with aiofiles.open(temp_file_path, 'r') as f:
        content_before_update = await f.read()

      # Create a dummy FileAccessPolicy instance
      dummy_file_access_policy = FakeFileAccessPolicy()
      command = UpdateDuendeMarkerImplementationCommand(
          file_access_policy=dummy_file_access_policy)
      marker_name = "my_marker"
      new_content = "print(\"new content\")"

      # Call the method that should only read the file
      updated_file_content = await command._get_updated_content(
          temp_file_path, marker_name, new_content)

      # Read the file content after calling _get_updated_content
      async with aiofiles.open(temp_file_path, 'r') as f:
        content_after_update = await f.read()

      # Assert that the file content has not changed on disk
